head.script:
scwin.memJson = $c.data.getMemInfo();
scwin.userId = scwin.memJson.userId;  //사용자

scwin.preRowPos = 0;
scwin.statusFlag = "";
scwin.ctrtNoRowCount = 0;

scwin.AreaInfoMap = {};			//Area 정보 저장하는 Map
scwin.FreightInfoMap = {};		//Freight 정보 저장하는 Map
scwin.CurrencyInfoMap = {};		//Currency 정보 저장하는 Map
scwin.ContainerTypeInfoMap = {};//Container Type 정보 저장하는 Map
scwin.CustomerInfoMap = {};		//Customer 정보 저장하는 Map

scwin.onpageload = function() {

	scwin.f_DefaultValue();
};

//초기화
scwin.btn_fieldClear_onclick = function (e) {

    $c.gus.cfInitObjects(tb_searchCondition,null);
    ds_OtherTariff.removeAll();
    scwin.f_DefaultValue();
};

scwin.f_DefaultValue = function() {

    scwin.f_Set("INIT");
    cnd_lc_iogb.setValue("");
    cnd_lc_workFlag.setValue("");
    cnd_lc_iogb.focus();
};

scwin.onUdcCompleted = function() {

    udc_bottomGrdBtnil.setDisabled(true); //udc disable 
};

scwin.f_Set = function(gubun) {

    switch ( gubun ) {
        case "INIT" : //초기화
            $c.gus.cfDisableBtn([btn_cancel, btn_save]);
            $c.gus.cfDisableBtnOnly([btn_deleteRowAll]);
            //udc_bottomGrdBtnil.setDisabled(true); //udc disable 
            scwin.statusFlag = "INIT";
            break;
        case "RETRIEVE" ://조회모드
            $c.gus.cfEnableBtnOnly([btn_addRow, btn_deleteRow, btn_undoRow, btn_deleteRowAll]);
            $c.gus.cfDisableBtnOnly([btn_cancel]);
            $c.gus.cfEnableBtnOnly([btn_save, btn_create]);
            scwin.statusFlag = "RETRIEVE";
            break;
        case "CREATE" :  //신규
            $c.gus.cfDisableBtnOnly([btn_create, btn_save]);
            $c.gus.cfEnableBtnOnly([btn_addRow, btn_deleteRow, btn_undoRow, btn_deleteRowAll]);
            $c.gus.cfEnableBtnOnly([btn_cancel, btn_save]);
            scwin.statusFlag = "CREATE";
            break;
        case "UPDATE" :	 //수정
            scwin.statusFlag = "UPDATE";
            break;
        case "SAVE" :	 //저장
            cfEnableBtnOnly([btn_save]);
            scwin.statusFlag = "SAVE";
            break;
        case "DELETE" :	 //삭제
            break;
    }
};

//조회
scwin.btn_retrieve_onclick = async function (e) {

    if (! await scwin.f_ReqFieldChk()) {
		return;
	}

    dma_SearchParam.set("iogb",cnd_lc_iogb.getValue());
    dma_SearchParam.set("locCd",cnd_ed_locCd.getValue());
    dma_SearchParam.set("fromDt",cnd_ed_fromDt.getValue());
    dma_SearchParam.set("workFlag",cnd_lc_workFlag.getValue());
    dma_SearchParam.set("cust",cnd_ed_cust.getValue());
    dma_SearchParam.set("kcomcd","DBEX");

    await $c.sbm.execute(sbm_retrieve);
};

//조회 callback
scwin.sbm_retrieve_submitdone = function() {

    let nCnt = ds_OtherTariff.getRowCount();

    if (nCnt == 0) {
		$c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
        total.setValue(nCnt);
		scwin.f_Set("INIT");
	} else {
        gr_OtherTariff.setFocusedCell(0, 0);
        total.setValue(nCnt);
        scwin.f_Set("RETRIEVE");
    }

    /*onloadcom*/
    gr_OtherTariff.setCellReadOnly(nCnt, "cust", true);
    gr_OtherTariff.setCellReadOnly(nCnt, "custnm", true);
    gr_OtherTariff.setCellReadOnly(nCnt, "iogb", true);
    gr_OtherTariff.setCellReadOnly(nCnt, "locCd", true);
    gr_OtherTariff.setCellReadOnly(nCnt, "locCdNm", true);
    gr_OtherTariff.setCellReadOnly(nCnt, "type", true);
    gr_OtherTariff.setCellReadOnly(nCnt, "fcode", true);
    gr_OtherTariff.setCellReadOnly(nCnt, "fcodenm", true);
    gr_OtherTariff.setCellReadOnly(nCnt, "fromDt", true);
    gr_OtherTariff.setCellReadOnly(nCnt, "curr", true);
};

scwin.f_ReqFieldChk = async function() {
    //필수입력항목 체크
	let validArry = [
		{ id: "cust", name: "Customer", mandatory: false, key: true } //cust:Customer:no::key,
		, { id: "iogb", name: "Export/Import", mandatory: true, key: true } //iogb:Export/Import:yes::key,
		, { id: "locCd", name: "Area", mandatory: true, key: true } //locCd:Area:yes::key,
		, { id: "type", name: "Unit", mandatory: true, key: true } //type:Unit:yes::key,
		, { id: "fcode", name: "Freight Code", mandatory: true, key: true } //fcode:Freight Code:yes::key,
		, { id: "curr", name: "Currency", mandatory: true, maxLength: 3, key: true } //curr:Currency:yes:length=3:key,
		, { id: "fromDt", name: "From Date", mandatory: true, maxLength: 8, valid: "date", format: "YYYYMMDD", key: true } //fromDt:From Date:yes:length=8&date=YYYYMMDD:key,
		, { id: "sellYn", name: "Sell", mandatory: true, key: true } //sellYn:Sell:yes::key,
		, { id: "buyYn", name: "buyYn", mandatory: true, key: true } //buyYn:buyYn:yes::key
	];
    let gridName = "Tariff List";

    let rtn = await $c.gus.cfValidateGrid(gr_OtherTariff, null, null, validArry, gridName);
    if (! rtn) {        
        return false;
    }
    return true;
};

scwin.udc_ilcomCode_loc_onclickEvent = function (e) {

    scwin.f_PopUp('Area', 'F', 'F', 'F');
};

//area pop callback
scwin.udc_ilcomCode_loc_callBackFunc = function(ret) {
