scwin.gr_OtherTariff_onrowindexchange = function (rowIndex, oldRow) {

    if (ds_OtherTariff.getRowStatusValue(rowIndex) == 2) {

		gr_OtherTariff.setCellReadOnly(rowIndex, "cust", false);
        gr_OtherTariff.setCellReadOnly(rowIndex, "custnm", false);
        gr_OtherTariff.setCellReadOnly(rowIndex, "iogb", false);
        gr_OtherTariff.setCellReadOnly(rowIndex, "locCd", false);
        gr_OtherTariff.setCellReadOnly(rowIndex, "type", false);
        gr_OtherTariff.setCellReadOnly(rowIndex, "fcode", false);
        gr_OtherTariff.setCellReadOnly(rowIndex, "fromDt", false);
        gr_OtherTariff.setCellReadOnly(rowIndex, "curr", false);

	} else {
        gr_OtherTariff.setCellReadOnly(rowIndex, "cust", true);
        gr_OtherTariff.setCellReadOnly(rowIndex, "custnm", true);
        gr_OtherTariff.setCellReadOnly(rowIndex, "iogb", true);
        gr_OtherTariff.setCellReadOnly(rowIndex, "locCd", true);
        gr_OtherTariff.setCellReadOnly(rowIndex, "locCdNm", true);
        gr_OtherTariff.setCellReadOnly(rowIndex, "type", true);
        gr_OtherTariff.setCellReadOnly(rowIndex, "fcode", true);
        gr_OtherTariff.setCellReadOnly(rowIndex, "fcodenm", true);
        gr_OtherTariff.setCellReadOnly(rowIndex, "fromDt", true);
        gr_OtherTariff.setCellReadOnly(rowIndex, "curr", true);
    }    
};

scwin.gr_OtherTariff_onafteredit = function (rowIndex, columnIndex, value) {
    if(rowIndex < 0) {
        return;
    }
    if(ds_OtherTariff.getRowCount() < rowIndex) {
        return;
    }

    let columnId = ds_OtherTariff.getColumnID(columnIndex);
    let columnValue = ds_OtherTariff.getCellData(rowIndex,columnIndex).trim();

    switch (columnId) {

        case "locCd":
            //코드값이 공백이 아닌경우 팝업을 호출한다.
            if (columnValue != ""){
                scwin.f_PopUpGrid("Area", rowIndex, "T", "F");
            } else {
                ds_OtherTariff.setCellData(rowIndex, "locCdNm", "");
            }
            break;

        case "fcode":
            //코드값이 공백이 아닌경우 팝업을 호출한다.
            if (columnValue != "" ){
                ds_OtherTariff.setCellData(rowIndex,"selpchItemCd", "");
                scwin.f_PopUpGrid("Freight", rowIndex, "T", "F");
            } else {
                ds_OtherTariff.setCellData(rowIndex, "fcodenm", "");
            }
            break;
        case "curr":
            //코드값이 공백이 아닌경우 팝업을 호출한다.
            if (columnValue != ""){
                scwin.f_PopUpGrid("Currency", rowIndex, "T", "F");
            }
            break;
        case "type":
            //코드값이 공백이 아닌경우 팝업을 호출한다.
            if (columnValue != ""){
                scwin.f_PopUpGrid("CNTR_TYPE", rowIndex, "T", "F");
            }
            break;
        case "cust":
            //코드값이 공백이 아닌경우 팝업을 호출한다.
            if (columnValue != ""){
                scwin.f_PopUpGrid("Customer", rowIndex, "T", "F");
            } else {
                ds_OtherTariff.setCellData(rowIndex, "custnm", "");
            }
            break;
        default:
            break;
    }
};

