//엑셀 업로드 끝난 후.
scwin.gr_OtherTariff_onfilereadend = async function (value) {
	let rowCount = ds_OtherTariff.getRowCount();
	for(var i = 0; i < rowCount; i++){

		if(ds_OtherTariff.getCellData(i, "iogb").toUpperCase() =="I"){
			ds_OtherTariff.setCellData(i, "iogb", "I");
		}else{
			ds_OtherTariff.setCellData(i, "iogb", "O");
		}

		let fromDT = ds_OtherTariff.getCellData(i, "fromDt");
		if(fromDT.indexOf("/") > -1){
			fromDT = fromDT.removeAll("/","");
		}
		if(fromDT.indexOf("-") > -1){
			fromDT = fromDT.removeAll("-","");
		}

		ds_OtherTariff.setCellData(i, "fromDt", fromDT);		
		ds_OtherTariff.setCellData(i, "kcomcd", "DBEX");

		//////Data 유효성 체크 시작.
		if (ds_OtherTariff.getCellData(i, "iogb").trim() == "") {
			await $c.win.alert((i+1) + " 행의 Export/Import 코드 오류입니다. 확인 하십시요.");
			ds_OtherTariff.removeAll();
			return;
		}

		//필수가 아닌경우 값이 없을경우 체크안함.
		//Customer Code이 있는 경우 팝업호출하여 유효성 체크
		let cust = ds_OtherTariff.getCellData(i, "cust").trim();
		if (cust != "") {
			if (await scwin.f_PopUpExcel("Customer", i, "T", "T", "K") != true ||
				ds_OtherTariff.getCellData(i, "cust").length < 6) {
				await $c.win.alert((i+1) + " 행의 Customer 코드 오류입니다. 확인 하십시요.");
				ds_OtherTariff.removeAll();
				return;
			}
		}
		//Area Code 팝업호출하여 유효성 체크
		let locCd = ds_OtherTariff.getCellData(i, "locCd").trim();
		if (locCd == "" || await scwin.f_PopUpExcel("Area", i, "T", "T", "K") != true) {
			await $c.win.alert((i+1) + " 행의 Area 코드 오류입니다. 확인 하십시요.");
			ds_OtherTariff.removeAll();
			return;
		}

		let type = ds_OtherTariff.getCellData(i, "type").trim();
		if (type == "" || await scwin.f_PopUpExcel("CNTR_TYPE", i, "T", "T", "K") != true) {
			await $c.win.alert((i+1) + " 행의 Unit 코드 오류입니다. 확인 하십시요.");
			ds_OtherTariff.removeAll();
			return;
		}

		let fcode = ds_OtherTariff.getCellData(i, "fcode").trim();
		if (fcode == "" || await scwin.f_PopUpExcel("Freight", i, "T", "T", "K") != true ||
			fcode.length < 3) {
			await $c.win.alert((i+1) + " 행의 Freight 코드 오류입니다. 확인 하십시요.");
			ds_OtherTariff.removeAll();
			return;
		}

		let fromDt = ds_OtherTariff.getCellData(i, "fromDt").trim();
		if (fromDt.length < 8) {
			await $c.win.alert((i+1) + " 행의 From Date 오류입니다. 확인 하십시요.");
			ds_OtherTariff.removeAll();
			return;
		}

		//필수가 아닌경우 값이 없을경우 체크안함.
		let curr = ds_OtherTariff.getCellData(i, "curr").trim();
		if (curr != "") {
			if (curr.length < 3 || await scwin.f_PopUpExcel("Currency", i, "T", "T", "K") != true) {
				await $c.win.alert((i+1) + " 행의 Currency 코드 오류입니다. 확인 하십시요.");
				ds_OtherTariff.removeAll();
				return;
			}
		}

	}

	//총건수 세팅
	total.setValue(rowCount);
	gr_OtherTariff.setFocusedCell(0, 0);
};

scwin.f_PopUpExcel = async function(disGubun, row, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {

	//매번 서버에 호출하게 되면 오래걸리므로 사전에 조회했던 값이 있으면 그걸 반환하고 아니면 서버에 호출하여 값을 받아오도록 한다.
	return await new Promise(function (resolve) {
		let searchKey = "";
        let searchData = null;
		switch (disGubun) {
			case "Area": //Area
				let locCd = ds_OtherTariff.getCellData(row, "locCd");
				if (locCd == null || locCd.trim() == "") {
                    resolve(false);
                    return;
                }

				//먼저 저장된 값이 있는지 판단해서 있으면 해당 값을 반환한다.
                searchKey = locCd.trim();
                searchData = scwin.AreaInfoMap[searchKey];
				if (searchData != undefined && searchData != null) {
                    $c.gus.cfSetGridReturnValue(searchData, ds_OtherTariff, row, "locCd", "locCdNm", [""]);
                    resolve(true);
                    return;
                }

				//저장된 값이 없으면 팝업을 띄워서 값을 받아온다.
				udc_grid_popUp.setSelectId("retrieveAreaCode");
				udc_grid_popUp.ilCommonPopUp(function(rtnList) {
						if (rtnList != "") {
							scwin.AreaInfoMap[searchKey] = rtnList;   //받아온 값을 저장해둔다.
							$c.gus.cfSetGridReturnValue(rtnList, ds_OtherTariff, row, "locCd", "locCdNm", [""]);
							resolve(true);
						} else {
							resolve(false);
						}
					}
					, locCd	 //코드
					, '' 	 //코드명
					, pWinCloseTF						// 결과가 1건 일때	원도우를	AutoClose 여부	(T:Close,F:Opened)
					, '2'								// 검색	결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 -	default	(2)
					, "Area Code,Area Name,"		// Title순서
					, '130,300'							// 보여주는 각 컬럼들의 폭
					, "3,4,5,6,7,8,9,10"					// 컬럼중에서 숨기는	컬럼 지정
					, null								// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
					, '500'								// POP-UP뛰을때 원도우의	사용자 정의	폭
					, '500'								// POP-UP뛰을때	우도우의	사용자 정의	높이
					, null								// 윈도우 위치 Y좌표
					, null								// 윈도우 위치 X좌표
					, null								// 중복체크여부	("F")
					, pAllSearchTF						// 전체검색허용여부	("F")
					, "Area Search,Area Code,Area Name"	// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
					, 'F'								// Data	건수가 0 일때 Window를 뛰우지 않음 리턴	: "N/A"
				);

				break;

			case "Freight"://Fleight
				let fcode = ds_OtherTariff.getCellData(row, "fcode");
				if (fcode == null || fcode.trim() == "") {
					resolve(false);
					return;
				}

				//먼저 저장된 값이 있는지 판단해서 있으면 해당 값을 반환한다.
				searchKey = fcode.trim();
				searchData = scwin.FreightInfoMap[searchKey];
				if (searchData != undefined && searchData != null) {
					$c.gus.cfSetGridReturnValue(searchData, ds_OtherTariff, row, "fcode", "fcodenm", [""]);
					resolve(true);
					return;
				}

				//저장된 값이 없으면 팝업을 띄워서 값을 받아온다.
				udc_grid_popUp.setSelectId("retriveFreightCodeInfo");
				udc_grid_popUp.ilCommonPopUp(function(rtnList) {
						var arry = ["", "selpchItemCd", "", "", "", "", "", ""];
						if (rtnList != "") {
							scwin.FreightInfoMap[searchKey] = rtnList;   //받아온 값을 저장해둔다.
							$c.gus.cfSetGridReturnValue(rtnList, ds_OtherTariff, row, "fcode", "fcodenm", arry);
							resolve(true);
						} else {
							resolve(false);
						}
					}
					, fcode	 //코드
					, ''	 //코드명
					, pWinCloseTF			// 결과가 1건 일때	원도우를	AutoClose 여부	(T:Close,F:Opened)
					, '10'				// 검색	결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 -	default	(2)
					, "Freight Code, Freight Name,"		// Title순서
					, '130,300'              // 보여주는 각 컬럼들의 폭
					, "3,4,5,6,7,8,9,10"     // 컬럼중에서 숨기는	컬럼 지정
					, null                   // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
