scwin.grid_popup = function(rowIndex, colIndex, newValue = null) {
	let columnId = gr_OtherTariff.getColumnID(colIndex);
    console.log("grid_popup call : " + columnId + ", newValue : " + newValue);
    if(newValue == null)
        return;

	let pCode = "";
	let pName = "";
	switch (columnId){
		case "locCd":
			scwin.f_PopUpGrid("Area", rowIndex, "T", "F");
			break;
		case "fcode":
			scwin.f_PopUpGrid("Freight", rowIndex, "T", "F");
			break;
		case "curr":
			scwin.f_PopUpGrid("Currency", rowIndex, "T", "F");
			break;
		case "type":
			scwin.f_PopUpGrid("CNTR_TYPE", rowIndex, "T", "F");
			break;
		case "cust":
			scwin.f_PopUpGrid("Customer", rowIndex, "T", "F");
			break;

		default:
			break;
	}
};

