				, pAllSearchTF			// 전체검색허용여부	("F")
				, "Currency Search,Currency Code,Currency Name"	// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
				, 'F'				// Data	건수가 0 일때 Window를 뛰우지 않음 리턴	: "N/A"
			);
			break;
		case "CNTR_TYPE"://Container Type
			udc_grid_popUp.setSelectId("retriveContainerTypeCodeInfo");	// XML상의 SELECT ID
			udc_grid_popUp.ilCommonPopUp(function(rtnList) {
                    if(rtnList.length == 1 && rtnList[0] == "N/A") {
                        rtnList = ["", "", "", "", "", "", "", "", ""];
                    }

					$c.gus.cfSetGridReturnValue(rtnList, ds_OtherTariff, row, "type", "", [""]);
				}
				, ds_OtherTariff.getCellData(row, "type")	 //코드
				, '' 	 //코드명
				, pWinCloseTF			// 결과가 1건 일때	원도우를	AutoClose 여부	(T:Close,F:Opened)
				, '10'				// 검색	결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 -	default	(2)
				, "Container Code, Container Name,"		// Title순서
				, '130,300'              // 보여주는 각 컬럼들의 폭
				, "3,4,5,6,7,8,9,10"     // 컬럼중에서 숨기는	컬럼 지정
				, null                   // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
				, '500'                  // POP-UP뛰을때 원도우의	사용자 정의	폭
				, '500'				// POP-UP뛰을때	우도우의	사용자 정의	높이
				, null				// 윈도우 위치 Y좌표
				, null				// 윈도우 위치 X좌표
				, null				// 중복체크여부	("F")
				, pAllSearchTF			// 전체검색허용여부	("F")
				, "Container Type Search,Container Code,Container Name"	// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
				, 'F'				// Data	건수가 0 일때 Window를 뛰우지 않음 리턴	: "N/A"
			);
			break;

		case "Customer": //Customer
			udc_grid_popUp.setSelectId("retrieveEngClntInfo");	// XML상의 SELECT ID
			udc_grid_popUp.ilCommonPopUp(function(rtnList) {
                    if(rtnList.length == 1 && rtnList[0] == "N/A") {
                        rtnList = ["", "", "", "", "", "", "", "", ""];
                    }

					$c.gus.cfSetGridReturnValue(rtnList, ds_OtherTariff, row, "cust", "custnm", [""]);
				}
				, ds_OtherTariff.getCellData(row, "cust")	 //코드
				, ""	 //코드명
				, pWinCloseTF			// 결과가 1건 일때	원도우를	AutoClose 여부	(T:Close,F:Opened)
				, '2'				// 검색	결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 -	default	(2)
				, "Customer Code,Customer Name,"		// Title순서
				, '130,300'              // 보여주는 각 컬럼들의 폭
				, "3,4,5,6,7,8,9,10"     // 컬럼중에서 숨기는	컬럼 지정
				, null                   // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
				, '500'                  // POP-UP뛰을때 원도우의	사용자 정의	폭
				, '500'				// POP-UP뛰을때	우도우의	사용자 정의	높이
				, null				// 윈도우 위치 Y좌표
				, null				// 윈도우 위치 X좌표
				, null				// 중복체크여부	("F")
				, pAllSearchTF			// 전체검색허용여부	("F")
				, "Customer Search,Customer Code,Customer Name"	// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
				, 'F'				// Data	건수가 0 일때 Window를 뛰우지 않음 리턴	: "N/A"
			);

			break;
		default:
			break;

	}
};

//-------------------------------------------------------------------------
// function	name : f_BeforePopUpEd
// function	desc : 공통팝업 열기 전에 체크- EMEDIT onKillFocus 이벤트	발생시
//					nmObj-코드명(text),	cdObj-코드(emedit),	gubun1
//-------------------------------------------------------------------------
scwin.f_BeforePopUpEd = function(nmObj, cdObj, gubun1, pWinCloseTF, pAllSearchTF) {
	let cdObjVal = cdObj.getValue().trim();
	if (cdObjVal == "") {
		nmObj.setValue("");
	} else {
		nmObj.setValue("");
		scwin.f_PopUp(gubun1, pWinCloseTF, pAllSearchTF);
	}
};

//-------------------------------------------------------------------------
// function	name : f_ChkPopUp
// function	desc : 팝업	처리시 검색된 데이터인 경우	팝업 처리 안함.
//------------------------------------------------------------------------
scwin.f_ChkPopUp = function(inObj, pairObj, disGubun, isCode) {

	// 값이	입력이 안된	경우, 해당 Text	Box가 readonly 인 경우,	이전값과 동일한	경우 팝업을	실행하지 않음.
	if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
		return;
	// 짝이	되는 오브젝트의	값 제거
	$c.gus.cfClearPairObj(pairObj);
	// 검색어 세팅
	let pVal = $c.gus.cfGetValue(inObj);
	// inObj가 코드	필드일 경우	팝업
	if (isCode == null || isCode == true)
		scwin.f_PopUp(disGubun, 'T', 'T', 'F');
	// inObj가 코드명 필드일 경우 팝업
	else
		scwin.f_PopUp(disGubun, 'T', 'T', 'F');
};

//grid addrow
scwin.addRow = function() {

    let rowIndex = ds_OtherTariff.getRowCount();

    ds_OtherTariff.insertRow(rowIndex);
    gr_OtherTariff.setFocusedCell(rowIndex, 0);

    ds_OtherTariff.setCellData(rowIndex, "kcomcd","DBEX") ;
    gr_OtherTariff.setFocusedCell(rowIndex,"iogb");

    if (ds_OtherTariff.getModifiedIndex().length > 0) {
        $c.gus.cfEnableBtnOnly([btn_save])
    }
};

scwin.delRow = function() {

    ds_OtherTariff.modifyRowStatus(ds_OtherTariff.getRowPosition(),"D");
};

scwin.undoRow = function() {
    let rowIndex = ds_OtherTariff.getRowPosition();
    if(ds_OtherTariff.getRowStatus(rowIndex) == "C") {
        ds_OtherTariff.removeRow(rowIndex);
    }   

	if (ds_OtherTariff.getModifiedIndex().length > 0) {
		$c.gus.cfEnableBtnOnly([btn_save]);
	}
};

//delete Allrow
scwin.btn_deleteRowAll_onclick = async function (e) {

    let confirm = await $c.win.confirm("전체 삭제을 적용하시겠습니까?")

    if( confirm ) {
        ds_OtherTariff.modifyAllStatus("D");
    }
    if (ds_OtherTariff.getModifiedIndex().length > 0) {
        $c.gus.cfEnableBtnOnly([btn_save])
    }
};

//cancel btn
scwin.btn_cancel_onclick = function (e) {

    ds_OtherTariff.removeAll();
	scwin.f_Set("RETRIEVE");	
};

scwin.btn_create_onclick = function (e) {

    ds_OtherTariff.removeAll();
    scwin.addRow();

    scwin.f_Set("CREATE");
};

//저장
scwin.btn_save_onclick = async function (e) {

    if (ds_OtherTariff.getModifiedIndex().length < 1) {
        await $c.win.alert("There have been no changes for Sea Other Tariff");//"@은(는) 변경된 사항이 없습니다.";
        return;
    }
    //필수사항 check
    if (await scwin.f_ReqFieldChk()) {

        let confirm = await $c.win.confirm("Do you wish to save?");
        if( confirm ) {

            $c.sbm.execute(sbm_save);
        }    
    }
};

//저장 callback
scwin.sbm_save_submitdone = function(e) {

	let body = e.responseJSON;
 	if(body.resultDataSet[0].Code == "0") {
		$c.gus.cfAlertMsg(E_MSG_CM_INF_001);	// 성공적으로 저장하였습니다
		scwin.btn_retrieve_onclick();
	}
};

//excelDw 
scwin.excelDw = async function() {

	if(ds_OtherTariff.getRowCount() == 0) {
		await $c.win.alert(E_MSG_CM_WRN_002);
		return;
	}

    let options = {
        fileName : "SeaOtherTariff.xlsx",
        sheetName : "SeaOtherTariff"
    }
    let infoArr = {};

	let rtn = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
	if(rtn) {
		$c.data.downloadGridViewExcel(gr_OtherTariff, options, infoArr)
	}
};

scwin.excelUp = async function() {

if (scwin.statusFlag != "CREATE") {
        await $c.win.alert("신규모드에서 실행 가능합니다.");
        return;
    }

    //UPLOAD 전 ds_OtherTariff 삭제.
    ds_OtherTariff.removeAll();

    let options = {};
    if(udc_gr_OtherTariff_topGrdBtn.getUpExt() == "1") {    //ASIS csv 는 헤더가 2줄이다.
        options = {
            "status": "C",
            "startRowIndex": 2,
            "type": "1",
            "expression" : "0"
        };
    } else {

        options = {
            "status": "C",
            "headerExist": 1,
            "type": "1",
            "startRowIndex": 0,
            "footerExist": 0,
        };
    }

    await udc_gr_OtherTariff_topGrdBtn.uploadGridViewExcel(gr_OtherTariff, options);
};

scwin.upperCaseDisplayFormatterFunc = function(value) {
    return value.toUpperCase();
}
